<template>
<div>
  <div class="thumbnail" @click="openModal(id)">
    <div class="caption">
      {{ Nom }}
    </div>
    <img :src="photo"/>
  </div> 

  <div :id="id" class="modal">
      <div class="modal-background"></div>
      <div class="modal-content">
        <div class="box">
        <p>
          {{ type }}
          {{ adresse }}
          {{ ville }}
          {{ pays }}
        </p>
      </div>
      </div>
      <button class="modal-close is-large" aria-label="close" @click="closeModal(id)"></button>
    </div> 
</div>          
</template>



<script>

export default {
  name: 'placeCard',
  props: {
    id: String,
    Nom: String, 
    photo: String, 
    type: Array, 
    adresse: String,
    ville: String, 
    pays: String
  },
  methods: {
    openModal(id) {
      console.log(id)
      document.getElementById(id).classList.add("is-active");
    },
    closeModal(id) {
      document.getElementById(id).classList.remove("is-active");
    }
  }
}
</script>



